--
-- Table structure for table `Kits`
--

DROP TABLE IF EXISTS `Kits`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `Kits` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `image_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `slug` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_featured` tinyint(1) DEFAULT '0',
  `stock_status` enum('in_stock','out_of_stock','pre_order') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'in_stock',
  `technical_specs` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`),
  KEY `idx_kits_slug` (`slug`),
  KEY `idx_kits_featured` (`is_featured`),
  KEY `idx_kits_stock` (`stock_status`),
  FULLTEXT KEY `idx_kits_search` (`name`,`description`)
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `Kits`
--

LOCK TABLES `Kits` WRITE;
/*!40000 ALTER TABLE `Kits` DISABLE KEYS */;
INSERT INTO `Kits` VALUES (1,'1.5KW Home Solar System','Compact  residential solar kit for lighting, phone charging, router backup, fan use, and small daily loads. Designed for starter homes, shops, and off-grid rooms.','/uploads/kits/1-5kw-kit-1782550919719-550521652.png','home-solar-system-1-5kw',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-28 09:47:26'),(2,'3.0KW Home Solar System','Entry  home solar package for small houses, shops, classrooms, and backup power with panels, inverter, LiFePO4 storage, mounting, cabling, and connectors.','/uploads/kits/3kw-1782468021741-636315567.png','home-solar-system-3kw',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-28 09:47:26'),(3,'6.2KW Home Solar System','Mid-size household and small business kit aligned to the 6.2KW home solar system family for refrigeration, lighting, entertainment, fans, and moderate appliance loads.','/uploads/kits/solar-kit-1782771351292-300183029.png','home-solar-system-6kw',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-29 22:15:52'),(4,'6.2KW-10KW Home Solar System','Large residential and light commercial solar system aligned to  6.2KW-10KW capacity bands with higher inverter capacity and scalable battery storage.','/uploads/kits/3kw2w-1782470388340-848507547.png','home-solar-system-10kw',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-28 09:47:26'),(5,'20KW-30KW Home Solar System','Large villa, estate, office, or compound solar system aligned to  20KW-30KW home solar system packaging.',NULL,'home-solar-system-20kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-28 09:47:26'),(6,'30KW Home and Facility Solar System','High-capacity solar system for compounds, facilities, farms, and offices with three-phase inverter capability and larger PV array sizing.',NULL,'home-solar-system-30kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(7,'30KW-50KW Commercial Solar System','Commercial solar kit for shops, offices, hotels, clinics, schools, warehouses, and small factories.',NULL,'commercial-solar-system-30-50kw',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(8,'60KW-100KW Commercial Solar System','Higher-capacity commercial solar kit for factories, malls, hotels, schools, and business facilities needing stronger energy cost control.',NULL,'commercial-solar-system-60-100kw',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(9,'120KW-180KW Industrial Solar System','Industrial solar package for warehouses, manufacturing, production sites, and high-consumption facilities.',NULL,'industrial-solar-system-120-180kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(10,'250KW-500KW Industrial Solar System','Project-scale solar and storage solution for industrial parks, large factories, logistics bases, and high-demand commercial sites.',NULL,'industrial-solar-system-250-500kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(11,'500KW Container Solar System','Containerized solar and storage solution for industrial power, microgrids, EV charging depots, and remote infrastructure.',NULL,'container-solar-system-500kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(12,'1MW Container Solar System','Large-scale containerized PV plus ESS solution for industrial sites, charging depots, and utility support projects.',NULL,'container-solar-system-1000kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(16,'1500W Solar Power Generator Kit','Portable solar power generator kit for emergency backup, outdoor work, camping, small shops, and mobile power.','/uploads/kits/3kw2w-1782468643894-557340461.png','solar-generator-1500w',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 10:10:45'),(17,'3000W Solar Power Generator Kit','Portable and semi-mobile solar power generator package for stronger backup, field teams, and small business use.','/uploads/kits/3kw2w-1782468569721-709798468.png','solar-generator-3000w',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 10:09:30'),(18,'6200W Solar Power Generator Kit','High-output solar power generator kit for remote sites, resilient household loads, and field operations.',NULL,'solar-generator-6200w',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(19,'Rack Battery Backup Kit 10.24kWh','Residential backup kit combining a 10.24kWh 3U low-voltage LiFePO4 battery with a compatible hybrid inverter.',NULL,'powerwall-battery-kit',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-29 19:51:49'),(20,'Rack Mounted Battery Kit','Rack-mounted LiFePO4 battery package for telecom, server room, commercial backup, and modular solar storage.','/uploads/kits/Screenshot-2026-06-29-235639-1782771866529-897098251.png','rack-battery-kit',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-29 22:24:27'),(21,'Solar Light and Fan Home Kit','Integrated home kit with solar panel, rechargeable battery, LED lighting, solar fan, and mobile charging for daily off-grid use.',NULL,'solar-light-fan-home-kit',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(22,'Agri Solar Kit','Solar kit for farms, irrigation support, borehole sites, livestock operations, rural lighting, and agricultural productivity.','/uploads/kits/agrisolar-1782469474487-455526562.png','agri-solar',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 10:24:35'),(23,'Solar EV Station Kit','PV plus ESS plus EV charging station kit for commercial parking, fleet yards, logistics bases, and clean transport projects.',NULL,'solar-ev-station',1,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(24,'3KW-8KW US Standard Dual Output Solar System','US standard dual-output residential solar system family for split load planning, backup circuits, and medium home energy independence.',NULL,'us-standard-dual-output-solar-system-3-8kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(25,'10KW-20KW US Standard Split-Phase Solar System','US standard split-phase solar system family for higher residential and light commercial requirements with larger PV input and lithium battery storage.',NULL,'us-standard-split-phase-solar-system-10-20kw',0,'in_stock',NULL,'2026-06-26 09:23:30','2026-06-26 09:23:30'),(30,'All-in-One ESS 30kW / 61kWh','Integrated hybrid energy storage system combining a 61kWh LiFePO4 battery, 30kW bidirectional PCS, EMS, grid and microgrid operation, optional dual MPPT solar charging, protection, and air-cooled thermal management.','/uploads/kits/Screenshot-2026-06-29-235533-1782771638611-874636951.png','all-in-one-ess-30kw-61kwh',0,'in_stock','{\"system\": {\"weight\": \"1.14t\", \"cycle_life\": \"3000+\", \"dimensions\": \"1000 x 800 x 2200mm\", \"efficiency\": \">=98%\", \"protection\": \"IP54\", \"scalability\": \"1-6 units\", \"communication\": \"CAN / RS485 / Ethernet / 4G\", \"battery_chemistry\": \"LiFePO4\", \"relative_humidity\": \"0-95%, non-condensing\", \"depth_of_discharge\": \"95%\", \"ambient_temperature\": \"-20C to 55C\", \"charge_discharge_rate\": \"0.5C / 1C\"}, \"battery\": {\"cooling\": \"Air cooled\", \"capacity\": \"61kWh / 200Ah\", \"configuration\": \"51.2V 200Ah modules\", \"voltage_range\": \"268.8-350.4V\", \"nominal_voltage\": \"307.2V\", \"maximum_charge_discharge_current\": \"200A\"}, \"grid_ac\": {\"thd\": \"<3%\", \"frequency\": \"50/60Hz\", \"output_power\": \"30kW\", \"power_factor\": \"-1 to 1 adjustable\", \"transfer_time\": \"20ms\", \"maximum_current\": \"136A\", \"nominal_voltage\": \"400/230V\"}, \"monitoring\": {\"display\": \"PC / control interface\", \"protocol\": \"Modbus TCP/IP\", \"communication\": \"RS485\", \"remote_control\": \"EMS cloud platform\"}, \"microgrid_ac\": {\"thd\": \"<3% with resistive load\", \"frequency\": \"50Hz (47-52Hz) or 60Hz (57-62Hz)\", \"maximum_power\": \"33kVA\", \"nominal_voltage\": \"400/230V\"}, \"optional_solar\": {\"mppt\": \"19.2kW + 19.2kW\", \"dc_voltage_range\": \"200-800V\"}, \"model_reference\": \"AI-VES61\"}','2026-06-29 19:51:49','2026-06-29 22:20:39'),(31,'AC-Coupled ESS 50kW / 107kWh','AC-coupled distributed energy storage system integrating a 107kWh LiFePO4 battery, 50kW bidirectional PCS, intelligent charge and discharge management, remote monitoring, fire protection, and forced-air converter cooling.','/uploads/kits/Screenshot-2026-06-29-233138-1782771490775-338168294.png','ac-coupled-ess-50kw-107kwh',0,'in_stock','{\"system\": {\"weight\": \"Approximately 1.3t\", \"wiring\": \"3P+N+PE\", \"cooling\": \"Battery air cooled; converter forced-air cooled\", \"altitude\": \"Up to 4000m; derating above 2000m\", \"ac_voltage\": \"400VAC\", \"cycle_life\": \">=6000 cycles\", \"dimensions\": \"1200 x 900 x 1650mm\", \"protection\": \"IP20\", \"installation\": \"Indoor or sheltered outdoor\", \"communication\": \"CAN / RS485 / Ethernet / 4G\", \"battery_chemistry\": \"LiFePO4\", \"relative_humidity\": \"0-95%, non-condensing\", \"ambient_temperature\": \"-20C to 55C\"}, \"battery\": {\"cell\": \"3.2V 280Ah LiFePO4\", \"capacity\": \"107kWh\", \"composition\": \"1P120S\", \"rated_power\": \"50kW\", \"rated_voltage\": \"384V\", \"voltage_range\": \"324-432V\", \"charge_discharge_rate\": \"0.5C\"}, \"model_reference\": \"AI-VES107\"}','2026-06-29 19:51:49','2026-06-29 22:18:11'),(32,'All-in-One ESS 50kW / 129kWh','Integrated hybrid energy storage system combining a 129kWh LiFePO4 battery, 50kW bidirectional PCS, EMS, optional dual MPPT solar charging, diesel-generator integration, protection, and air-cooled thermal management.','/uploads/kits/Screenshot-2026-06-29-235557-1782771455472-247914031.png','all-in-one-ess-50kw-129kwh',0,'in_stock','{\"system\": {\"weight\": \"1.6t\", \"cycle_life\": \"6000+\", \"dimensions\": \"1000 x 1200 x 2360mm\", \"efficiency\": \">=98%\", \"protection\": \"IP54\", \"scalability\": \"1-6 units\", \"communication\": \"CAN / RS485 / Ethernet / 4G\", \"battery_chemistry\": \"LiFePO4\", \"relative_humidity\": \"0-95%, non-condensing\", \"depth_of_discharge\": \"95%\", \"ambient_temperature\": \"-20C to 55C\", \"charge_disc