  `container_units` varchar(20) NOT NULL,
  `warranty_info` varchar(200) NOT NULL,
  `degradation` varchar(200) NOT NULL,
  `source_pages` varchar(30) NOT NULL,
  PRIMARY KEY (`product_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

