DELETE FROM `ProductSpecifications` WHERE `product_id` BETWEEN 2701 AND 2746;
DELETE FROM `ProductModels` WHERE `product_id` BETWEEN 2701 AND 2746;
DELETE FROM `Products` WHERE `id` BETWEEN 2701 AND 2746;

INSERT INTO `Products`
  (`id`,`category_id`,`name`,`price`,`description`,`wattage`,`durability_rating`,`battery_type`,`warranty_info`,`image_url`,`manual_pdf_url`,`video_url`,`metadata`,`is_featured`,`stock_status`,`created_at`,`updated_at`)
SELECT
  c.product_id,
  1,
  c.name,
  0.00,
  CONCAT(c.build_label, ' solar module family covering ', c.wattage, ' with ', c.cell_arrangement, ', ', c.dimensions, ', and a maximum efficiency of ', c.max_efficiency, '. Suitable for rooftop, commercial, and ground-mount photovoltaic systems.'),
  c.wattage,
  c.build_label,
  NULL,
  c.warranty_info,
  NULL,
  NULL,
  NULL,
  JSON_OBJECT(
    'series', c.series_code,
    'technology', c.technology,
    'build', c.build_label,
    'cell_arrangement', c.cell_arrangement,
    'dimensions', c.dimensions,
    'weight', c.weight_kg,
    'maximum_efficiency', c.max_efficiency
  ),
  0,
  'in_stock',
  '2026-06-30 08:45:00',
  '2026-06-30 08:45:00'
FROM `tmp_solar_catalog` c
ORDER BY c.product_id;

INSERT INTO `ProductModels`
  (`id`,`product_id`,`model_code`,`display_name`,`nominal_power`,`price`,`stock_status`,`is_default`,`sort_order`,`created_at`,`updated_at`)
SELECT
  m.model_id,
  m.product_id,
  m.model_code,
  m.model_code,
  m.nominal_power,
  NULL,
  'in_stock',
  CASE WHEN m.sort_order = 0 THEN 1 ELSE 0 END,
  m.sort_order,
  '2026-06-30 08:45:00',
  '2026-06-30 08:45:00'
FROM `tmp_solar_models` m
ORDER BY m.model_id;

