UPDATE `KitProducts`
SET
  `quantity` = CASE
    WHEN `product_id` = 101 THEN GREATEST(1, ROUND(`quantity` * 300 / 405))
    WHEN `product_id` = 106 THEN GREATEST(1, ROUND(`quantity` * 200 / 405))
    ELSE `quantity`
  END,
  `product_id` = CASE
    WHEN `product_id` IN (101,106) THEN 2733
    WHEN `product_id` = 102 THEN 2734
    WHEN `product_id` = 103 THEN 2714
    WHEN `product_id` = 104 THEN 2704
    WHEN `product_id` = 105 THEN 2745
    ELSE `product_id`
  END,
  `product_model_id` = NULL
WHERE `product_id` BETWEEN 101 AND 106;

UPDATE `KitProducts`
SET `product_model_id` = CASE
  WHEN `product_id` = 2733 THEN 460147
  WHEN `product_id` = 2734 THEN 460150
  WHEN `product_id` = 2714 THEN 460066
  WHEN `product_id` = 2704 THEN 460017
  WHEN `product_id` = 2745 THEN 460184
  ELSE `product_model_id`
END
WHERE `product_id` IN (2704,2714,2733,2734,2745);

DELETE FROM `Products` WHERE `category_id` = 1 AND `id` BETWEEN 101 AND 106;

